CREATE OR REPLACE FUNCTION docs_ut.test_document_create()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_j jsonb;
  v_jc jsonb;
  v_r record;
  v_page_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM docs.document WHERE tenant_id = 'test';
  DELETE FROM docs.charter WHERE tenant_id = 'test';

  -- A4 portrait
  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, '{"name":"Test A4"}'::jsonb));
  SELECT * INTO v_r FROM docs.document WHERE id = v_j->>'id';
  RETURN NEXT is(v_r.width, 210::numeric, 'A4 width = 210');
  RETURN NEXT is(v_r.height, 297::numeric, 'A4 height = 297');
  RETURN NEXT is(v_r.format, 'A4', 'format stored');
  RETURN NEXT is(v_r.orientation, 'portrait', 'orientation default portrait');
  RETURN NEXT is(v_j->>'slug', 'general-test-a4', 'slug from category+name');

  SELECT count(*)::int INTO v_page_cnt FROM docs.page WHERE doc_id = v_j->>'id';
  RETURN NEXT is(v_page_cnt, 1, 'first page auto-created');

  -- A3 landscape
  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, '{"name":"Test A3 L","format":"A3","orientation":"landscape"}'::jsonb));
  SELECT * INTO v_r FROM docs.document WHERE id = v_j->>'id';
  RETURN NEXT is(v_r.width, 420::numeric, 'A3 landscape width = 420');
  RETURN NEXT is(v_r.height, 297::numeric, 'A3 landscape height = 297');

  -- HD
  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, '{"name":"Test HD","format":"HD"}'::jsonb));
  SELECT * INTO v_r FROM docs.document WHERE id = v_j->>'id';
  RETURN NEXT is(v_r.width, 1920::numeric, 'HD width = 1920');
  RETURN NEXT is(v_r.height, 1080::numeric, 'HD height = 1080');

  -- With charte
  v_jc := docs.charter_create(jsonb_populate_record(NULL::docs.charter, jsonb_build_object(
    'name', 'Test DC', 'color_bg', '#fff', 'color_main', '#000', 'color_accent', '#f00',
    'color_text', '#333', 'color_text_light', '#888', 'color_border', '#eee',
    'font_heading', 'Inter', 'font_body', 'Inter'
  )));
  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, jsonb_build_object('name', 'With Charter', 'charter_id', v_jc->>'id')));
  SELECT * INTO v_r FROM docs.document WHERE id = v_j->>'id';
  RETURN NEXT is(v_r.charter_id, v_jc->>'id', 'charter linked');

  DELETE FROM docs.document WHERE tenant_id = 'test';
  DELETE FROM docs.charter WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_document_create() IS 'Test document creation — jsonb returns, format→dimensions';

CREATE OR REPLACE FUNCTION docs_ut.test_document_duplicate()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_j jsonb;
  v_dup text;
  v_src_pages int;
  v_dup_pages int;
  v_dup_html text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM docs.document WHERE tenant_id = 'test';

  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, '{"name":"Original"}'::jsonb));
  PERFORM docs.page_set_html(v_j->>'id', 0, '<div data-id="h">Hello</div>');
  PERFORM docs.page_add(v_j->>'id', 'P2', '<p>Page 2</p>');

  v_dup := docs.document_duplicate(v_j->>'id', 'Copy');

  RETURN NEXT ok(v_dup IS NOT NULL, 'duplicate returns new id');
  RETURN NEXT ok(v_dup != v_j->>'id', 'different id');
  RETURN NEXT is((SELECT name FROM docs.document WHERE id = v_dup), 'Copy', 'new name');
  RETURN NEXT is((SELECT format FROM docs.document WHERE id = v_dup), 'A4', 'format copied');

  SELECT count(*)::int INTO v_src_pages FROM docs.page WHERE doc_id = v_j->>'id';
  SELECT count(*)::int INTO v_dup_pages FROM docs.page WHERE doc_id = v_dup;
  RETURN NEXT is(v_dup_pages, v_src_pages, 'same page count');

  SELECT html INTO v_dup_html FROM docs.page WHERE doc_id = v_dup AND page_index = 0;
  RETURN NEXT is(v_dup_html, '<div data-id="h">Hello</div>', 'HTML cloned');

  DELETE FROM docs.document WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_document_duplicate() IS 'Test document duplicate — deep clone, jsonb create';

CREATE OR REPLACE FUNCTION docs_ut.test_document_print_css()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_j jsonb;
  v_css text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM docs.document WHERE tenant_id = 'test';

  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, '{"name":"Print A4"}'::jsonb));
  v_css := docs.document_print_css(v_j->>'id');
  RETURN NEXT ok(v_css LIKE '%size: 210mm 297mm%', 'A4 portrait @page size');
  RETURN NEXT ok(v_css LIKE '%break-after: page%', 'break-after present');
  RETURN NEXT ok(v_css LIKE '%.doc-print-page%', 'print page class present');

  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, '{"name":"Print A3L","format":"A3","orientation":"landscape"}'::jsonb));
  v_css := docs.document_print_css(v_j->>'id');
  RETURN NEXT ok(v_css LIKE '%size: 297mm 420mm%', 'A3 landscape @page size swapped');

  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, '{"name":"Print HD","format":"HD"}'::jsonb));
  v_css := docs.document_print_css(v_j->>'id');
  RETURN NEXT ok(v_css LIKE '%size: 1920mm 1080mm%', 'HD @page size (no swap)');

  RETURN NEXT ok(docs.document_print_css('nonexistent') IS NULL, 'NULL for unknown doc');

  DELETE FROM docs.document WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_document_print_css() IS 'Test document_print_css — @page dimensions, jsonb create';

