CREATE OR REPLACE FUNCTION docs_ut.test_layout_check()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_result text;
BEGIN
  -- Within bounds
  v_html := '<div data-id="ok" style="width:200mm;height:290mm">Fits</div>';
  v_result := docs.layout_check(v_html, 210, 297);
  RETURN NEXT ok(v_result IS NULL, 'within bounds returns NULL');

  -- Width overflow
  v_html := '<div data-id="wide" style="width:220mm;height:100mm">Wide</div>';
  v_result := docs.layout_check(v_html, 210, 297);
  RETURN NEXT ok(v_result IS NOT NULL, 'width overflow detected');
  RETURN NEXT ok(v_result LIKE '%[wide]%', 'overflow references data-id');

  -- Height overflow
  v_html := '<div data-id="tall" style="width:100mm;height:300mm">Tall</div>';
  v_result := docs.layout_check(v_html, 210, 297);
  RETURN NEXT ok(v_result LIKE '%height%', 'height overflow detected');

  -- No dimensions = no overflow
  v_html := '<div data-id="nodim" style="color:red">No dims</div>';
  v_result := docs.layout_check(v_html, 210, 297);
  RETURN NEXT ok(v_result IS NULL, 'no dimensions = no overflow');
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_layout_check() IS 'Test layout_check — elements within/outside canvas';

CREATE OR REPLACE FUNCTION docs_ut.test_library_assets()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_j jsonb;
  v_asset_id uuid;
  v_cnt int;
  v_role text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM docs.library WHERE tenant_id = 'test';

  v_j := docs.library_create(jsonb_populate_record(NULL::docs.library, '{"name":"Test Lib"}'::jsonb));

  SELECT id INTO v_asset_id FROM asset.asset LIMIT 1;
  IF v_asset_id IS NULL THEN
    RETURN NEXT skip('no assets in database');
    DELETE FROM docs.library WHERE tenant_id = 'test';
    RETURN;
  END IF;

  PERFORM docs.library_add_asset(v_j->>'id', v_asset_id, 'hero', 'Photo principale pleine largeur');
  SELECT count(*)::int INTO v_cnt FROM docs.library_asset WHERE library_id = v_j->>'id';
  RETURN NEXT is(v_cnt, 1, 'asset added');

  SELECT role INTO v_role FROM docs.library_asset WHERE library_id = v_j->>'id' AND asset_id = v_asset_id;
  RETURN NEXT is(v_role, 'hero', 'role stored');

  PERFORM docs.library_add_asset(v_j->>'id', v_asset_id, 'background', 'Fond de page');
  SELECT role INTO v_role FROM docs.library_asset WHERE library_id = v_j->>'id' AND asset_id = v_asset_id;
  RETURN NEXT is(v_role, 'background', 'role updated via upsert');

  RETURN NEXT ok(docs.library_remove_asset(v_j->>'id', v_asset_id), 'remove returns true');
  SELECT count(*)::int INTO v_cnt FROM docs.library_asset WHERE library_id = v_j->>'id';
  RETURN NEXT is(v_cnt, 0, 'asset removed');

  RETURN NEXT ok(NOT docs.library_remove_asset(v_j->>'id', v_asset_id), 'remove nonexistent returns false');

  DELETE FROM docs.library WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_library_assets() IS 'Test library add/remove assets — jsonb create';

