END;
$function$;
COMMENT ON FUNCTION docs_ut.test_library_create() IS 'Test library creation — jsonb return, unique name';

CREATE OR REPLACE FUNCTION docs_ut.test_library_delete()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_j jsonb;
  v_jd jsonb;
  v_asset_id uuid;
  v_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM docs.document WHERE tenant_id = 'test';
  DELETE FROM docs.library WHERE tenant_id = 'test';

  v_j := docs.library_create(jsonb_populate_record(NULL::docs.library, '{"name":"To Delete"}'::jsonb));

  SELECT id INTO v_asset_id FROM asset.asset LIMIT 1;
  IF v_asset_id IS NOT NULL THEN
    PERFORM docs.library_add_asset(v_j->>'id', v_asset_id, 'test');
  END IF;

  v_jd := docs.document_create(jsonb_populate_record(NULL::docs.document, jsonb_build_object('name', 'Linked Doc', 'library_id', v_j->>'id')));

  RETURN NEXT ok(docs.library_delete(v_j->>'id') IS NOT NULL, 'delete returns true');

  SELECT count(*)::int INTO v_cnt FROM docs.library WHERE id = v_j->>'id';
  RETURN NEXT is(v_cnt, 0, 'library removed');

  RETURN NEXT ok(
    (SELECT library_id IS NULL FROM docs.document WHERE id = v_jd->>'id'),
    'document library_id set to NULL'
  );

  RETURN NEXT ok(docs.library_delete('nonexistent-id') IS NULL, 'delete unknown returns false');

  DELETE FROM docs.document WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_library_delete() IS 'Test library delete — cascade, FK SET NULL, jsonb return';

CREATE OR REPLACE FUNCTION docs_ut.test_library_read()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_j jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM docs.library WHERE tenant_id = 'test';

  v_j := docs.library_create(jsonb_populate_record(NULL::docs.library, '{"name":"Read Test","description":"Test library"}'::jsonb));

  v_j := docs.library_read(v_j->>'id');

  RETURN NEXT ok(v_j->>'id' IS NOT NULL, 'library_read returns data');
  RETURN NEXT is(v_j->>'name', 'Read Test', 'name in result');
  RETURN NEXT is(v_j->>'description', 'Test library', 'description');

  RETURN NEXT ok(docs.library_read('nonexistent') IS NULL, 'NULL for unknown library');

  DELETE FROM docs.library WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_library_read() IS 'Test library read — jsonb return';

CREATE OR REPLACE FUNCTION docs_ut.test_normalize_color()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT is(docs.normalize_color('#ff0080'), '#ff0080', 'hex 6 lowercase unchanged');
  RETURN NEXT is(docs.normalize_color('#FF0080'), '#ff0080', 'hex 6 uppercase');
  RETURN NEXT is(docs.normalize_color('#FFF'), '#ffffff', 'hex 3 → 6');
  RETURN NEXT is(docs.normalize_color('#abc'), '#aabbcc', 'hex 3 lowercase');
  RETURN NEXT is(docs.normalize_color('rgb(255, 0, 128)'), '#ff0080', 'rgb()');
  RETURN NEXT is(docs.normalize_color('rgb(0, 0, 0)'), '#000000', 'rgb black');
  RETURN NEXT ok(docs.normalize_color('not-a-color') IS NULL, 'invalid returns NULL');
  RETURN NEXT ok(docs.normalize_color('red') IS NULL, 'named color returns NULL');
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_normalize_color() IS 'Test normalize_color — hex 3/6 digits, rgb(), invalid';

CREATE OR REPLACE FUNCTION docs_ut.test_page_add_remove()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_j jsonb;
  v_idx int;
  v_cnt int;
  v_names text[];
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM docs.document WHERE tenant_id = 'test';

  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, '{"name":"Pages Test"}'::jsonb));

  v_idx := docs.page_add(v_j->>'id', 'Page 2');
  RETURN NEXT is(v_idx, 1, 'page_add returns index 1');

  v_idx := docs.page_add(v_j->>'id', 'Page 3');
  RETURN NEXT is(v_idx, 2, 'page_add returns index 2');

  SELECT count(*)::int INTO v_cnt FROM docs.page WHERE doc_id = v_j->>'id';
  RETURN NEXT is(v_cnt, 3, '3 pages total');

  RETURN NEXT ok(docs.page_remove(v_j->>'id', 1), 'remove page 1');

  SELECT count(*)::int INTO v_cnt FROM docs.page WHERE doc_id = v_j->>'id';
  RETURN NEXT is(v_cnt, 2, '2 pages after remove');

  SELECT array_agg(name ORDER BY page_index) INTO v_names FROM docs.page WHERE doc_id = v_j->>'id';
  RETURN NEXT is(v_names, ARRAY['Page 1', 'Page 3'], 'pages renumbered correctly');

  PERFORM docs.page_remove(v_j->>'id', 1);
  BEGIN
    PERFORM docs.page_remove(v_j->>'id', 0);
    RETURN NEXT fail('should raise on last page');
  EXCEPTION WHEN OTHERS THEN
    RETURN NEXT pass('raises on last page removal');
  END;

  DELETE FROM docs.document WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_page_add_remove() IS 'Test page add/remove — jsonb document create';

CREATE OR REPLACE FUNCTION docs_ut.test_page_set_html()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_j jsonb;
  v_cnt int;
  v_rev_cnt int;
  v_html text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  DELETE FROM docs.document WHERE tenant_id = 'test';

  v_j := docs.document_create(jsonb_populate_record(NULL::docs.document, '{"name":"HTML Test"}'::jsonb));
  PERFORM docs.page_set_html(v_j->>'id', 0, '<div data-id="v1">Version 1</div>');

  v_cnt := docs.page_set_html(v_j->>'id', 0, '<div data-id="v2">Version 2</div><span data-id="s1">Span</span>');
  RETURN NEXT is(v_cnt, 2, 'returns 2 data-id elements');

  SELECT html INTO v_html FROM docs.page WHERE doc_id = v_j->>'id' AND page_index = 0;
  RETURN NEXT ok(v_html LIKE '%Version 2%', 'HTML updated');

  SELECT count(*)::int INTO v_rev_cnt FROM docs.page_revision WHERE doc_id = v_j->>'id' AND page_index = 0;
  RETURN NEXT is(v_rev_cnt, 1, '1 revision saved');

  RETURN NEXT is(
    (SELECT html FROM docs.page_revision WHERE doc_id = v_j->>'id' AND page_index = 0 AND version = 1),
    '<div data-id="v1">Version 1</div>', 'revision has old HTML');

  v_cnt := docs.page_set_html(v_j->>'id', 0, '<p data-id="v3">V3</p>');
  SELECT count(*)::int INTO v_rev_cnt FROM docs.page_revision WHERE doc_id = v_j->>'id' AND page_index = 0;
  RETURN NEXT is(v_rev_cnt, 2, '2 revisions after second update');

  DELETE FROM docs.document WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_page_set_html() IS 'Test page_set_html — HTML saved, revision created, jsonb create';

CREATE OR REPLACE FUNCTION docs_ut.test_style_merge()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- jsonb keys are sorted alphabetically
  RETURN NEXT is(docs.style_merge('width:210mm;color:red', 'color:blue;font-size:4mm'),
    'color:blue;width:210mm;font-size:4mm', 'merge with overwrite');
  RETURN NEXT is(docs.style_merge('', 'color:red'), 'color:red', 'empty existing');
  RETURN NEXT is(docs.style_merge('width:10mm', ''), 'width:10mm', 'empty new');
  RETURN NEXT is(docs.style_merge(NULL, 'a:b'), 'a:b', 'NULL existing');
  RETURN NEXT is(docs.style_merge('a:1;b:2', 'b:3;c:4'), 'a:1;b:3;c:4', 'partial overwrite');
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_style_merge() IS 'Test style_merge — basic merge, overwrite, new properties';

CREATE OR REPLACE FUNCTION docs_ut.test_xhtml_patch()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_result text;
BEGIN
  -- STYLE: add style to element without style
  v_html := '<div data-id="a">Hello</div>';
  v_result := docs.xhtml_patch(v_html, '[{"id":"a","style":{"color":"red"}}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%style="color:red"%', 'style added to unstyled element');

  -- STYLE: merge with existing
  v_html := '<div data-id="a" style="width:10mm">Hello</div>';
  v_result := docs.xhtml_patch(v_html, '[{"id":"a","style":{"color":"blue"}}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%color:blue%', 'style merged: new prop');
  RETURN NEXT ok(v_result LIKE '%width:10mm%', 'style merged: existing prop preserved');

  -- CONTENT: replace innerHTML
  v_html := '<div data-id="a">Old content</div>';
  v_result := docs.xhtml_patch(v_html, '[{"id":"a","content":"New content"}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%New content%', 'content replaced');
  RETURN NEXT ok(v_result NOT LIKE '%Old content%', 'old content gone');

  -- REMOVE: delete element
  v_html := '<div data-id="keep">Keep</div><div data-id="rm">Remove me</div>';
  v_result := docs.xhtml_patch(v_html, '[{"id":"rm","remove":true}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%Keep%', 'kept element preserved');
  RETURN NEXT ok(v_result NOT LIKE '%Remove me%', 'removed element gone');

  -- INSERT: add before closing tag
  v_html := '<div data-id="container"><p>Existing</p></div>';
  v_result := docs.xhtml_patch(v_html, '[{"id":"container","insert":"<p>Added</p>"}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%<p>Existing</p><p>Added</p>%', 'inserted before end');

  -- REPLACE: replace entire element
  v_html := '<div data-id="old">Old</div>';
  v_result := docs.xhtml_patch(v_html, '[{"id":"old","replace":"<span data-id=\"new\">New</span>"}]'::jsonb);
  RETURN NEXT ok(v_result LIKE '%<span data-id="new">New</span>%', 'element replaced');
  RETURN NEXT ok(v_result NOT LIKE '%data-id="old"%', 'old element gone');

  -- INVALID: patch that breaks XML
  BEGIN
    v_html := '<div data-id="a">Hello</div>';
    PERFORM docs.xhtml_patch(v_html, '[{"id":"a","content":"<b>unclosed"}]'::jsonb);
    RETURN NEXT fail('should raise on invalid XML');
  EXCEPTION WHEN OTHERS THEN
    RETURN NEXT pass('raises on invalid XML result');
  END;

  -- Unknown data-id: no-op
  v_html := '<div data-id="a">Hello</div>';
  v_result := docs.xhtml_patch(v_html, '[{"id":"unknown","content":"X"}]'::jsonb);
  RETURN NEXT is(v_result, v_html, 'unknown data-id is no-op');
END;
$function$;
COMMENT ON FUNCTION docs_ut.test_xhtml_patch() IS 'Test xhtml_patch — style, content, remove, insert, replace, invalid';

